import React, { useState, useEffect, useRef } from 'react';
import io from 'socket.io-client';
import Editor from '@monaco-editor/react';
import { ToastContainer, toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import axios from 'axios';
import { 
  Users, 
  Code2, 
  Bot, 
  Play, 
  Share2,
  X,
  ArrowLeft,
  ChevronDown,
  RefreshCw,
  Terminal,
  Copy,
  Download,
  LogOut,
  LogIn,
  UserPlus,
  Sparkles,
  AlertTriangle,
  CheckCircle,
  ChevronRight,
  ChevronLeft,
  Save,
  FolderPlus,
  User,
  Mail,
  Lock,
  Eye,
  EyeOff,
  Home,
  Globe,
  Settings,
  HelpCircle,
  Bell,
  Search
} from 'lucide-react';
import './App.css';
import { useAuth } from './AuthContext';

// Initialize socket
const socket = io(process.env.REACT_APP_SOCKET_URL || 'http://localhost:5000', {
  transports: ['websocket', 'polling'],
  reconnection: true,
  reconnectionAttempts: 10,
  reconnectionDelay: 1000,
  timeout: 20000
});

// Supported languages
const LANGUAGE_OPTIONS = [
  { id: 'javascript', name: 'JavaScript', extension: 'js' },
  { id: 'python', name: 'Python', extension: 'py' },
  { id: 'java', name: 'Java', extension: 'java' },
  { id: 'cpp', name: 'C++', extension: 'cpp' },
  { id: 'c', name: 'C', extension: 'c' },
  { id: 'csharp', name: 'C#', extension: 'cs' },
  { id: 'php', name: 'PHP', extension: 'php' },
  { id: 'ruby', name: 'Ruby', extension: 'rb' },
  { id: 'go', name: 'Go', extension: 'go' },
  { id: 'rust', name: 'Rust', extension: 'rs' },
  { id: 'typescript', name: 'TypeScript', extension: 'ts' },
  { id: 'html', name: 'HTML', extension: 'html' },
  { id: 'css', name: 'CSS', extension: 'css' },
  { id: 'sql', name: 'SQL', extension: 'sql' }
];

// OT Utilities
const OTUtils = {
  createOperationFromChange: (change) => {
    if (!change || !change.changes || change.changes.length === 0) return null;
    
    const monacoChange = change.changes[0];
    if (monacoChange.rangeLength > 0) {
      return {
        type: 'delete',
        position: monacoChange.rangeOffset,
        length: monacoChange.rangeLength
      };
    } else if (monacoChange.text) {
      return {
        type: 'insert',
        position: monacoChange.rangeOffset,
        text: monacoChange.text
      };
    }
    return null;
  },

  applyOperationToEditor: (editor, operation) => {
    if (!editor || !operation) return;
    
    try {
      const model = editor.getModel();
      if (!model) return;
      
      if (operation.type === 'insert') {
        const position = model.getPositionAt(operation.position);
        editor.executeEdits('remote', [{
          range: new window.monaco.Range(
            position.lineNumber,
            position.column,
            position.lineNumber,
            position.column
          ),
          text: operation.text,
          forceMoveMarkers: true
        }]);
      } else if (operation.type === 'delete') {
        const startPos = model.getPositionAt(operation.position);
        const endPos = model.getPositionAt(operation.position + operation.length);
        editor.executeEdits('remote', [{
          range: new window.monaco.Range(
            startPos.lineNumber,
            startPos.column,
            endPos.lineNumber,
            endPos.column
          ),
          text: '',
          forceMoveMarkers: true
        }]);
      }
    } catch (error) {
      console.error('Error applying operation:', error);
    }
  }
};

