      setDocumentVersion(version);
      
      if (updateUser !== username) {
        toast.info(`${updateUser} made changes`);
      }
    };

    const handleUsersUpdate = (users) => {
      console.log('Users updated:', users);
      setOnlineUsers(users);
    };

    const handleUserJoined = (userData) => {
      toast.info(`${userData.username} joined the room`);
    };

    const handleUserLeft = (userData) => {
      toast.warning(`${userData.username} left the room`);
    };

    const handleLanguageUpdate = (newLanguage) => {
      setLanguage(newLanguage);
      toast.info(`Language changed to ${newLanguage}`);
    };

    const handleSyncResponse = (operations, state) => {
      if (editorRef.current) {
        operations.forEach(op => {
          OTUtils.applyOperationToEditor(editorRef.current, op);
        });
      }
      if (state) {
        setCode(state.content);
        setDocumentVersion(state.version);
      }
      setIsSyncing(false);
      toast.info('Synced with latest version');
    };

    const handleError = (error) => {
      console.error('Socket error:', error);
      toast.error(error.message || 'Connection error');
      setIsSyncing(false);
    };

    // Attach listeners
    socket.on('connect', handleConnect);
    socket.on('document-state', handleDocumentState);
    socket.on('code-update', handleCodeUpdate);
    socket.on('users-update', handleUsersUpdate);
    socket.on('user-joined', handleUserJoined);
    socket.on('user-left', handleUserLeft);
    socket.on('language-update', handleLanguageUpdate);
    socket.on('sync-response', handleSyncResponse);
    socket.on('error', handleError);

    // Clean up
    return () => {
      socket.off('connect', handleConnect);
      socket.off('document-state', handleDocumentState);
      socket.off('code-update', handleCodeUpdate);
      socket.off('users-update', handleUsersUpdate);
      socket.off('user-joined', handleUserJoined);
      socket.off('user-left', handleUserLeft);
      socket.off('language-update', handleLanguageUpdate);
      socket.off('sync-response', handleSyncResponse);
      socket.off('error', handleError);
    };
  }, [roomId, username, userId]);

  const handleEditorChange = (value, change) => {
    if (change && change.changes && change.changes.length > 0) {
      const operation = OTUtils.createOperationFromChange(change);
      
      if (operation) {
        socket.emit('code-change', operation, roomId);
      }
    }
    setCode(value);
  };

  const handleEditorMount = (editor) => {
    editorRef.current = editor;
    
    // Set up cursor tracking
    editor.onDidChangeCursorPosition((e) => {
      const position = editor.getModel().getOffsetAt(e.position);
      socket.emit('cursor-update', position, roomId);
    });

    // Focus the editor
    editor.focus();
  };

  const handleLanguageChange = (newLanguage) => {
    setLanguage(newLanguage);
    socket.emit('language-change', newLanguage, roomId);
  };

  const handleRunCode = async () => {
    if (!code.trim()) {
      toast.error('No code to run');
      return;
    }

    setIsRunning(true);
    setTerminalOutput(`$ Running ${language} code...\n\n`);

    try {
      const response = await axios.post(`${process.env.REACT_APP_API_URL}/execute`, {
        code,
        language,
        input: inputData
      });

      if (response.data.success) {
        setTerminalOutput(prev => prev + '✓ Execution successful!\n' + response.data.output);
        toast.success('Code executed successfully!');
      } else {
        setTerminalOutput(prev => prev + '✗ Execution failed!\n' + response.data.output);
        toast.error('Code execution failed');
      }
    } catch (error) {
      setTerminalOutput(prev => prev + '✗ Error: ' + (error.response?.data?.output || error.message));
      toast.error('Failed to execute code');
    } finally {
      setIsRunning(false);
    }
  };

  const handleAIRequest = async (prompt) => {
    if (prompt.trim()) {
      setIsAnalyzing(true);
      try {
        // Use Gemini API for AI completion
        const response = await axios.post(`${process.env.REACT_APP_API_URL}/test-ai`, {
          prompt,
          context: code,
          language
        });
        
        if (response.data.completion) {
          setAiResponse(response.data.completion);
          toast.success('AI completion ready!');
        } else {
          setAiResponse('// AI service is currently unavailable. Please try again later.');
          toast.error('AI service error');
        }
      } catch (error) {
        setAiResponse(`// AI Error: ${error.message}\n\nFor AI features, please ensure the Gemini API key is configured in the backend.`);
        toast.error('AI service unavailable');
      } finally {
        setIsAnalyzing(false);
        setAiPrompt('');
      }
    }
  };

  const handleCodeAnalysis = async () => {
    if (code.trim()) {
      setIsAnalyzing(true);
      try {
        const response = await axios.post(`${process.env.REACT_APP_API_URL}/analyze`, {
          code,
          language
        });
        
        if (response.data.analysis) {
          setAiResponse(response.data.analysis);
          toast.success('Code analysis complete!');
        } else {
          setAiResponse('Code analysis service is currently unavailable.');
          toast.error('Analysis service error');
        }
      } catch (error) {
        setAiResponse(`Analysis Error: ${error.message}`);
        toast.error('Analysis failed');
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  const applyAICompletion = () => {
    if (aiResponse && editorRef.current) {
      const position = editorRef.current.getPosition();
      const operation = {
        type: 'insert',
        position: editorRef.current.getModel().getOffsetAt(position),
        text: '\n' + aiResponse
      };
      socket.emit('code-change', operation, roomId);
      setAiResponse('');
      toast.success('AI completion applied!');
    }
  };

  const syncDocument = () => {
    setIsSyncing(true);
    socket.emit('sync-request', documentVersion, roomId);
  };

  const shareRoom = () => {
    navigator.clipboard.writeText(roomId);
    toast.success('Room ID copied to clipboard!');
  };

  const downloadCode = () => {
    const blob = new Blob([code], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `unified-ide-${roomId}-${Date.now()}.${LANGUAGE_OPTIONS.find(l => l.id === language)?.extension || 'txt'}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast.success('Code downloaded!');
  };

  const saveProject = async () => {
    try {
      const response = await axios.post(`${process.env.REACT_APP_API_URL}/projects`, {
        name: `Project ${roomId}`,
        description: `Collaborative project from room ${roomId}`,
        language,
        code,
        isPublic: false
      });
      
      if (response.data.success) {
        toast.success('Project saved successfully!');
      }
    } catch (error) {
      toast.error('Failed to save project');
    }
  };

  const clearTerminal = () => {
    setTerminalOutput('');
  };

  const leaveRoom = () => {
    if (socketRef.current) {
      socketRef.current.disconnect();
    }
    onLeaveRoom();
  };

  const currentUserCount = onlineUsers.length;
  const isCurrentUser = (user) => user.username === username;

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-left">
          <Code2 className="logo-icon" />
          <h1>Unified IDE</h1>
        </div>
        
        <div className="header-center">
          <div className="room-info">
            <span className="user-info">
              Room: <strong style={{ color: '#00d4aa' }}>{roomId}</strong>
            </span>
            <span className="user-info">
              as <strong>{username}</strong>
            </span>
            
            <LanguageSelector 
              currentLanguage={language} 
              onLanguageChange={handleLanguageChange} 
            />
            
            <button 
              onClick={syncDocument} 
              className="btn btn-sm btn-secondary"
              disabled={isSyncing}
              title="Sync with latest version"
            >
              <RefreshCw size={14} className={isSyncing ? 'spin' : ''} />
              {isSyncing ? 'Syncing...' : `v${documentVersion}`}
            </button>
            
            <button onClick={shareRoom} className="btn btn-sm btn-secondary" title="Share room">
              <Share2 size={14} />
              Share
            </button>
            
            <button onClick={saveProject} className="btn btn-sm btn-success" title="Save project">
              <Save size={14} />
              Save
            </button>
            
            <button onClick={downloadCode} className="btn btn-sm btn-secondary" title="Download code">
              <Download size={14} />
              Export
            </button>
          </div>
        </div>

        <div className="header-right">
          <div 
            className="online-users-toggle"
            onClick={() => setShowUsersPopup(!showUsersPopup)}
          >
            <Users size={18} />
            <span>{currentUserCount} online</span>
          </div>

          <button 
            onClick={leaveRoom} 
            className="btn btn-sm btn-warning"
            title="Leave room"
          >
            <LogOut size={14} />
            Leave
          </button>

          {showUsersPopup && (
            <div className="users-popup">
              <div className="popup-header">
                <h4>Online Users ({currentUserCount})</h4>
                <button 
                  onClick={() => setShowUsersPopup(false)}
                  className="close-btn"
                >
                  <X size={16} />
                </button>
              </div>
              <div className="popup-users-list">
                {onlineUsers.map((user, index) => (
                  <div 
                    key={user.id || index} 
                    className={`popup-user-item ${isCurrentUser(user) ? 'current-user' : ''}`}
                  >
                    <div className="user-avatar"></div>
                    <span>{user.username} {isCurrentUser(user) && '(You)'}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </header>

      <div className="main-content">
        <div className="editor-section">
          <div className="editor-header">
            <h3>
              {LANGUAGE_OPTIONS.find(l => l.id === language)?.name || language} Editor • 
              <span className={isSyncing ? 'status-syncing' : 'status-online'} style={{ marginLeft: '8px', fontSize: '12px' }}>
                {isSyncing ? 'Syncing...' : 'Real-time Active'}
              </span>
            </h3>
            <div className="editor-actions">
              <button 
                onClick={handleRunCode} 
                className="btn btn-success"
                disabled={isRunning}
              >
                <Play size={16} />
                {isRunning ? 'Running...' : 'Run Code'}
              </button>
              <button 
                onClick={handleCodeAnalysis} 
                className="btn btn-warning"
                disabled={isAnalyzing}
              >
                <AlertTriangle size={16} />
                {isAnalyzing ? 'Analyzing...' : 'Analyze'}
              </button>
            </div>
          </div>
          
          <div className="monaco-container">
            <Editor
              height="100%"
              language={language}
              value={code}
              onChange={handleEditorChange}
              onMount={handleEditorMount}
              theme="vs-dark"
              options={{
                minimap: { enabled: true },
                fontSize: 14,
                wordWrap: 'on',
                automaticLayout: true,
                scrollBeyondLastLine: false,
                renderLineHighlight: 'all',
                cursorBlinking: 'smooth',
                cursorSmoothCaretAnimation: 'on',
                smoothScrolling: true,
                formatOnPaste: true,
                formatOnType: true,
                suggestOnTriggerCharacters: true,
                acceptSuggestionOnEnter: 'on',
                tabCompletion: 'on',
                wordBasedSuggestions: true,
                parameterHints: { enabled: true },
              }}
            />
          </div>
        </div>

        <div className={`sidebar ${isSidebarExpanded ? '' : 'collapsed'}`}>
          {!isSidebarExpanded ? (
            <button 
              className="sidebar-toggle"
              onClick={() => setIsSidebarExpanded(true)}
            >
              <ChevronLeft size={20} />
            </button>
          ) : (
            <>
              <button 
                className="sidebar-toggle"
                onClick={() => setIsSidebarExpanded(false)}
              >
                <ChevronRight size={20} />
              </button>
              
              <AISection
                aiPrompt={aiPrompt}
                setAiPrompt={setAiPrompt}
                aiResponse={aiResponse}
                onRequestAI={handleAIRequest}
                onApplyAI={applyAICompletion}
                language={language}
                isAnalyzing={isAnalyzing}
              />
              
              <TerminalSection
                output={terminalOutput}
                onClear={clearTerminal}
                isExpanded={terminalExpanded}
                onToggle={() => setTerminalExpanded(!terminalExpanded)}
                isRunning={isRunning}
              />
              
              <div className="sidebar-section">
                <div className="section-header">
                  <Settings className="section-icon" />
                  <h3>Input Data</h3>
                </div>
                <div className="section-content">
                  <div className="input-group">
                    <label>Standard Input (for code execution)</label>
                    <textarea
                      placeholder="Enter input data for your program..."
                      value={inputData}
                      onChange={(e) => setInputData(e.target.value)}
                      className="ai-textarea"
                      rows="3"
                      disabled={isRunning}
                    />
                  </div>
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      <ToastContainer
        position="bottom-right"
        autoClose={3000}
        hideProgressBar={false}
        newestOnTop
        closeOnClick
        rtl={false}
        pauseOnFocusLoss
        draggable
        pauseOnHover
        theme="dark"
      />
    </div>
  );
}

// ===== MAIN APP COMPONENT =====

function App() {
  const { user, logout, isAuthenticated } = useAuth();
  const [currentView, setCurrentView] = useState('landing');
  const [currentRoom, setCurrentRoom] = useState(null);
  const [currentUsername, setCurrentUsername] = useState('');
  const [currentUserId, setCurrentUserId] = useState(null);

  useEffect(() => {
    // Redirect to landing page if not authenticated and trying to access protected pages
    if (!isAuthenticated && currentView !== 'landing' && currentView !== 'login' && currentView !== 'register') {
      setCurrentView('landing');
    }
  }, [isAuthenticated, currentView]);

  const handleNavigate = (view) => {
    // Check authentication for protected pages
    if ((view === 'create' || view === 'join') && !isAuthenticated) {
      setCurrentView('login');
    } else {
      setCurrentView(view);
    }
  };

  const handleLoginSuccess = (userData, redirectTo = null) => {
    if (redirectTo === 'login') {
      setCurrentView('login');
    } else if (userData) {
      if (redirectTo) {
        setCurrentView(redirectTo);
      } else {
        setCurrentView('landing');
      }
    }
  };

  const handleLogout = () => {
    logout();
    setCurrentView('landing');
    toast.success('Logged out successfully');
  };

  const handleJoinRoom = (roomId, username, userId = null) => {
    setCurrentRoom(roomId);
    setCurrentUsername(username);
    setCurrentUserId(userId);
    setCurrentView('editor');
  };

  const handleLeaveRoom = () => {
    setCurrentRoom(null);
    setCurrentUsername('');
    setCurrentUserId(null);
    setCurrentView('landing');
  };

  // Render based on current view
  switch (currentView) {
    case 'register':
      return <RegisterPage onBack={() => setCurrentView('landing')} onLoginSuccess={handleLoginSuccess} />;
    
    case 'login':
      return <LoginPage 
        onBack={() => setCurrentView('landing')} 
        onRegister={() => setCurrentView('register')} 
        onLoginSuccess={handleLoginSuccess}
      />;
    
    case 'create':
      return <CreateRoomPage 
        onBack={() => setCurrentView('landing')} 
        onJoinRoom={handleJoinRoom}
        user={user}
      />;
    
    case 'join':
      return <JoinRoomPage 
        onBack={() => setCurrentView('landing')} 
        onJoinRoom={handleJoinRoom}
        user={user}
      />;
    
    case 'editor':
      return <EditorPage 
        roomId={currentRoom} 
        username={currentUsername}
        userId={currentUserId}
        onLeaveRoom={handleLeaveRoom}
      />;
    
    default: // 'landing'
      return (
        <>
          <LandingPage 
            onNavigate={handleNavigate}
            user={user}
            onLogout={handleLogout}
          />
          <ToastContainer
            position="bottom-right"
            autoClose={3000}
            hideProgressBar={false}
            newestOnTop
            closeOnClick
            rtl={false}
            pauseOnFocusLoss
            draggable
            pauseOnHover
            theme="dark"
          />
        </>
      );
  }
}

export default App;
